# Instead of pasting all hex data, let me build a more efficient approach.
# I'll concatenate all the raw data and scan through it.

# For brevity, I'll just process the first sector to establish the pattern,
# then use the same logic on all data.

def scan_blocks(data, base_addr):
    """Scan a byte array for valid blocks. 
    Headers are at positions where (offset % 16) == 8.
    Sentinel $AA at header[7]."""
    blocks = []
    offset = 8  # First possible header position
    while offset + 8 <= len(data):
        if data[offset + 7] == 0xAA:
            entry_pc = data[offset] | (data[offset+1] << 8)
            exit_pc = data[offset+2] | (data[offset+3] << 8)
            code_len = data[offset+4]
            epilogue_offset = data[offset+5]
            flags = data[offset+6]
            
            blocks.append({
                'header_addr': base_addr + offset,
                'entry_pc': entry_pc,
                'exit_pc': exit_pc,
                'code_len': code_len,
                'epilogue_offset': epilogue_offset,
                'flags': flags,
                'offset_in_sector': offset,
            })
        offset += 16  # Check every 16-byte aligned position
    return blocks

