# Better approach: scan each hex string for the AA sentinel pattern
# A valid header is 8 bytes where byte[7] = 0xAA, at offset (16k+8) 

def find_blocks_in_hex(hex_str, sector_base_addr):
    """Find all valid blocks in a hex string (4096 bytes = one sector)."""
    data = bytes.fromhex(hex_str.replace(" ", ""))
    assert len(data) == 4096, f"Expected 4096 bytes, got {len(data)}"
    
    blocks = []
    # Check every 16-byte aligned position minus 8
    # Header at offset 8, 24, 40, 56, ..., 4088
    for offset in range(8, 4096, 16):
        if offset + 8 > 4096:
            break
        sentinel = data[offset + 7]
        if sentinel == 0xAA:
            entry_pc = data[offset] | (data[offset+1] << 8)
            exit_pc = data[offset+2] | (data[offset+3] << 8)
            code_len = data[offset+4]
            epilogue_offset = data[offset+5]
            flags = data[offset+6]
            
            blocks.append({
                'prg_addr': sector_base_addr + offset,
                'entry_pc': entry_pc,
                'exit_pc': exit_pc,
                'code_len': code_len,
                'epilogue_offset': epilogue_offset,
                'flags': flags,
            })
    return blocks

